import { getPermissionsCacheEntry } from '@linm-soft-org/linm-web-common-components';
import { normalizePath } from '../router/navigateInAppPath';
import { resolveExternalContentUrl } from './shellUrlConfig';
import { isStandalone } from '../dev/isStandalone';

export const MENU_TYPE_SHELL = 'shell';

export interface ShellNavMenuItem {
  path: string;
  defaultUrl: string;
  menuType?: string | null;
}

function readShellNavItems(): ShellNavMenuItem[] {
  const raw = getPermissionsCacheEntry()?.payload?.navItems;
  if (!Array.isArray(raw)) return [];

  const items: ShellNavMenuItem[] = [];
  for (const item of raw) {
    const row = item as {
      path?: string | null;
      defaultUrl?: string | null;
      menuType?: string | null;
    };
    if (!row.path || !row.defaultUrl) continue;
    if ((row.menuType ?? 'route') !== MENU_TYPE_SHELL) continue;
    items.push({
      path: normalizePath(row.path),
      defaultUrl: row.defaultUrl.trim(),
      menuType: row.menuType,
    });
  }
  return items.sort((a, b) => b.path.length - a.path.length);
}

function joinExternalUrl(base: string, suffix: string): string {
  if (!suffix) return base;
  try {
    const url = new URL(base);
    const extra = suffix.startsWith('/') ? suffix : `/${suffix}`;
    url.pathname = `${url.pathname.replace(/\/$/, '')}${extra}`;
    return url.toString();
  } catch {
    const trimmed = base.replace(/\/$/, '');
    const extra = suffix.startsWith('/') ? suffix : `/${suffix}`;
    return `${trimmed}${extra}`;
  }
}

/** Resolve iframe URL from menu type=shell (longest path prefix match). */
export function resolveShellEmbedUrl(pathname: string): string | null {
  const current = normalizePath(pathname);
  for (const item of readShellNavItems()) {
    if (current === item.path || current.startsWith(`${item.path}/`)) {
      const suffix = current.slice(item.path.length);
      return joinExternalUrl(item.defaultUrl, suffix);
    }
  }
  if (isStandalone) {
    return resolveExternalContentUrl() || null;
  }
  return null;
}

/** First segment of shell menu paths — used for Root MFE route registration. */
export function listShellRoutePrefixes(): string[] {
  const prefixes = new Set<string>();
  for (const item of readShellNavItems()) {
    const seg = item.path.split('/').filter(Boolean)[0];
    if (seg) prefixes.add(seg);
  }
  return [...prefixes];
}
